proof_block:
// The previous attempt asserted cross-run equalities directly in the body,
// but the ensures conjuncts about `post1_self_` / `post2_self_` form the
// LHS of an implication (P ==> det_equal); they are NOT hypotheses in the
// body. We wrap every cross-run assertion inside `if <P> { ... }` so that
// P becomes a path condition. Then inside we (a) align the two runs via
// the pre-state and explicit cross-run triggers, and (b) close the final
// Map ext-equal on each `*_perms@` from (dom equal) + (addr from wf) +
// (is_init from wf) + (value equal via the cross-run get_X equalities).

let queue0 = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let owning_c = pre_self_.get_thread(queue0).owning_container;

if post1_self_.wf()
    && post1_self_.page_closure() =~= pre_self_.page_closure()
    && post1_self_.proc_dom() =~= pre_self_.proc_dom()
    && post1_self_.endpoint_dom() == pre_self_.endpoint_dom()
    && post1_self_.container_dom() == pre_self_.container_dom()
    && post1_self_.thread_dom() == pre_self_.thread_dom()
    && (forall|p_ptr: ProcPtr|
            #![trigger post1_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|c_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(c_ptr)]
            pre_self_.container_dom().contains(c_ptr) && c_ptr != owning_c
                ==> post1_self_.get_container(c_ptr)
                    =~= pre_self_.get_container(c_ptr))
    && (forall|c_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(c_ptr)]
            pre_self_.container_dom().contains(c_ptr)
                ==> post1_self_.get_container(c_ptr).subtree_set
                    =~= pre_self_.get_container(c_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr) && t_ptr != queue0
                ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post1_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post1_self_.get_endpoint(e_ptr).owning_container)
    && post1_self_.get_thread(queue0).endpoint_descriptors
        =~= pre_self_.get_thread(queue0).endpoint_descriptors
    && post1_self_.get_container(owning_c).owned_procs
        =~= pre_self_.get_container(owning_c).owned_procs
    && post1_self_.get_container(owning_c).owned_threads
        =~= pre_self_.get_container(owning_c).owned_threads
    && post1_self_.get_container(owning_c).children
        =~= pre_self_.get_container(owning_c).children
    && post1_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1)
    && post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads
    && post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter
    && post1_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state
    && post2_self_.wf()
    && post2_self_.page_closure() =~= pre_self_.page_closure()
    && post2_self_.proc_dom() =~= pre_self_.proc_dom()
    && post2_self_.endpoint_dom() == pre_self_.endpoint_dom()
    && post2_self_.container_dom() == pre_self_.container_dom()
    && post2_self_.thread_dom() == pre_self_.thread_dom()
    && (forall|p_ptr: ProcPtr|
            #![trigger post2_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|c_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(c_ptr)]
            pre_self_.container_dom().contains(c_ptr) && c_ptr != owning_c
                ==> post2_self_.get_container(c_ptr)
                    =~= pre_self_.get_container(c_ptr))
    && (forall|c_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(c_ptr)]
            pre_self_.container_dom().contains(c_ptr)
                ==> post2_self_.get_container(c_ptr).subtree_set
                    =~= pre_self_.get_container(c_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr) && t_ptr != queue0
                ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post2_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post2_self_.get_endpoint(e_ptr).owning_container)
    && post2_self_.get_thread(queue0).endpoint_descriptors
        =~= pre_self_.get_thread(queue0).endpoint_descriptors
    && post2_self_.get_container(owning_c).owned_procs
        =~= pre_self_.get_container(owning_c).owned_procs
    && post2_self_.get_container(owning_c).owned_threads
        =~= pre_self_.get_container(owning_c).owned_threads
    && post2_self_.get_container(owning_c).children
        =~= pre_self_.get_container(owning_c).children
    && post2_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1)
    && post2_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads
    && post2_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter
    && post2_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state
{
    // ---- 1. Cross-run domain equalities (each post.X_dom() equals pre.X_dom()). ----
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.container_dom() == post2_self_.container_dom());
    assert(post1_self_.thread_dom() == post2_self_.thread_dom());
    assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());

    // ---- 2. Cross-run pointwise equalities through pre_self_. ----
    // For each get_X(_) the post1 and post2 ensures use *disjoint* triggers
    // (`post1_self_.get_X(_)` vs `post2_self_.get_X(_)`), so we force both
    // to be instantiated at the same key by re-asserting them.
    assert forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) implies
            post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
    by {
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    };

    assert forall|c_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
        pre_self_.container_dom().contains(c_ptr) implies
            post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
    by {
        if c_ptr != owning_c {
            assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        } else {
            // For the affected container, individual field equalities
            // (owned_procs / owned_threads / children / subtree_set) agree
            // pointwise; that suffices for Container struct equality via =~=.
            assert(post1_self_.get_container(owning_c).owned_procs
                =~= pre_self_.get_container(owning_c).owned_procs);
            assert(post2_self_.get_container(owning_c).owned_procs
                =~= pre_self_.get_container(owning_c).owned_procs);
            assert(post1_self_.get_container(owning_c).owned_threads
                =~= pre_self_.get_container(owning_c).owned_threads);
            assert(post2_self_.get_container(owning_c).owned_threads
                =~= pre_self_.get_container(owning_c).owned_threads);
            assert(post1_self_.get_container(owning_c).children
                =~= pre_self_.get_container(owning_c).children);
            assert(post2_self_.get_container(owning_c).children
                =~= pre_self_.get_container(owning_c).children);
            assert(post1_self_.get_container(owning_c).subtree_set
                =~= pre_self_.get_container(owning_c).subtree_set);
            assert(post2_self_.get_container(owning_c).subtree_set
                =~= pre_self_.get_container(owning_c).subtree_set);
        }
    };

    assert forall|t_ptr: ThreadPtr|
        #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) implies
            post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
    by {
        if t_ptr != queue0 {
            assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
            assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        } else {
            // For the popped thread, only endpoint_descriptors is pinned.
            assert(post1_self_.get_thread(queue0).endpoint_descriptors
                =~= pre_self_.get_thread(queue0).endpoint_descriptors);
            assert(post2_self_.get_thread(queue0).endpoint_descriptors
                =~= pre_self_.get_thread(queue0).endpoint_descriptors);
        }
    };

    assert forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) implies
            post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
    by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        if e_ptr != endpoint_ptr {
            assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
            assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        } else {
            assert(post1_self_.get_endpoint(endpoint_ptr).queue@
                =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
            assert(post2_self_.get_endpoint(endpoint_ptr).queue@
                =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
            assert(post1_self_.get_endpoint(endpoint_ptr).queue@
                =~= post2_self_.get_endpoint(endpoint_ptr).queue@);
            assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
                == post2_self_.get_endpoint(endpoint_ptr).owning_threads);
            assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
                == post2_self_.get_endpoint(endpoint_ptr).rf_counter);
            assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
                == post2_self_.get_endpoint(endpoint_ptr).queue_state);
            assert(pre_self_.get_endpoint(endpoint_ptr).owning_container
                =~= post1_self_.get_endpoint(endpoint_ptr).owning_container);
            assert(pre_self_.get_endpoint(endpoint_ptr).owning_container
                =~= post2_self_.get_endpoint(endpoint_ptr).owning_container);
        }
    };

    // ---- 3. Map view equalities via extensionality. ----
    // Domains agree: both equal pre's via `*_dom()` ensures and the inline
    // identity `X_dom() == X_perms@.dom()`.
    assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom()) by {
        assert(post1_self_.container_perms@.dom() == post1_self_.container_dom());
        assert(post2_self_.container_perms@.dom() == post2_self_.container_dom());
    };
    assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom()) by {
        assert(post1_self_.process_perms@.dom() == post1_self_.proc_dom());
        assert(post2_self_.process_perms@.dom() == post2_self_.proc_dom());
    };
    assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom()) by {
        assert(post1_self_.thread_perms@.dom() == post1_self_.thread_dom());
        assert(post2_self_.thread_perms@.dom() == post2_self_.thread_dom());
    };
    assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom()) by {
        assert(post1_self_.endpoint_perms@.dom() == post1_self_.endpoint_dom());
        assert(post2_self_.endpoint_perms@.dom() == post2_self_.endpoint_dom());
    };

    // Pointwise PointsTo equality at each key: same addr (from wf), same
    // is_init (from wf), same value (from get_X equal across runs above).
    assert forall|c_ptr: ContainerPtr|
        post1_self_.container_perms@.dom().contains(c_ptr) implies
            post1_self_.container_perms@[c_ptr] == post2_self_.container_perms@[c_ptr]
    by {
        assert(post1_self_.container_dom().contains(c_ptr));
        assert(post2_self_.container_dom().contains(c_ptr));
        assert(post1_self_.container_perms@[c_ptr].addr() == c_ptr);
        assert(post2_self_.container_perms@[c_ptr].addr() == c_ptr);
        assert(post1_self_.container_perms@[c_ptr].is_init());
        assert(post2_self_.container_perms@[c_ptr].is_init());
        assert(post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr));
        assert(post1_self_.container_perms@[c_ptr].value()
            == post2_self_.container_perms@[c_ptr].value());
    };
    assert forall|p_ptr: ProcPtr|
        post1_self_.process_perms@.dom().contains(p_ptr) implies
            post1_self_.process_perms@[p_ptr] == post2_self_.process_perms@[p_ptr]
    by {
        assert(post1_self_.proc_dom().contains(p_ptr));
        assert(post2_self_.proc_dom().contains(p_ptr));
        assert(post1_self_.process_perms@[p_ptr].addr() == p_ptr);
        assert(post2_self_.process_perms@[p_ptr].addr() == p_ptr);
        assert(post1_self_.process_perms@[p_ptr].is_init());
        assert(post2_self_.process_perms@[p_ptr].is_init());
        assert(post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr));
        assert(post1_self_.process_perms@[p_ptr].value()
            == post2_self_.process_perms@[p_ptr].value());
    };
    assert forall|t_ptr: ThreadPtr|
        post1_self_.thread_perms@.dom().contains(t_ptr) implies
            post1_self_.thread_perms@[t_ptr] == post2_self_.thread_perms@[t_ptr]
    by {
        assert(post1_self_.thread_dom().contains(t_ptr));
        assert(post2_self_.thread_dom().contains(t_ptr));
        assert(post1_self_.thread_perms@[t_ptr].addr() == t_ptr);
        assert(post2_self_.thread_perms@[t_ptr].addr() == t_ptr);
        assert(post1_self_.thread_perms@[t_ptr].is_init());
        assert(post2_self_.thread_perms@[t_ptr].is_init());
        assert(post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        assert(post1_self_.thread_perms@[t_ptr].value()
            == post2_self_.thread_perms@[t_ptr].value());
    };
    assert forall|e_ptr: EndpointPtr|
        post1_self_.endpoint_perms@.dom().contains(e_ptr) implies
            post1_self_.endpoint_perms@[e_ptr] == post2_self_.endpoint_perms@[e_ptr]
    by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(post1_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
        assert(post2_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
        assert(post1_self_.endpoint_perms@[e_ptr].is_init());
        assert(post2_self_.endpoint_perms@[e_ptr].is_init());
        assert(post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        assert(post1_self_.endpoint_perms@[e_ptr].value()
            == post2_self_.endpoint_perms@[e_ptr].value());
    };

    // Final map ext-equal.
    assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);
    assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);
    assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);
    assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);

    // Return-value equality (both are unit).
    assert(r1 == r2);
}
